<script>
	import { onMount } from "svelte";

	// Spelaren
	let top = 50;
	let left = 50;
	const playerSize = 60;

	// Målet
	let goalTop = 200;
	let goalLeft = 200;
	const goalSize = 60;

	let target = { x: goalLeft, y: goalTop };
	const speed = 10;

	let winner = false;

	function onKeyDown(e) {
		if (winner) return; // Stoppa rörelse efter vinst

		switch(e.key.toLowerCase()) {
			case "w": top -= 20; break;
			case "s": top += 20; break;
			case "a": left -= 20; break;
			case "d": left += 20; break;
		}

		checkCollision();
	}

	function randomTarget() {
		const x = Math.random() * (window.innerWidth - goalSize);
		const y = Math.random() * (window.innerHeight - goalSize);
		return { x, y };
	}

	function moveGoal() {
		if (winner) return; // stoppa målet om spelaren vunnit

		const dx = target.x - goalLeft;
		const dy = target.y - goalTop;
		const distance = Math.sqrt(dx*dx + dy*dy);

		if (distance < speed) {
			target = randomTarget();
		} else {
			goalLeft += (dx / distance) * speed;
			goalTop += (dy / distance) * speed;
		}

		checkCollision();
		requestAnimationFrame(moveGoal);
	}

	function checkCollision() {
		// Enkel rektangel-kollision
		if (
			left < goalLeft + goalSize &&
			left + playerSize > goalLeft &&
			top < goalTop + goalSize &&
			top + playerSize > goalTop
		) {
			winner = true;
		}
	}

	onMount(() => {
		target = randomTarget();
		moveGoal();
	});
</script>

<style>
	body {
		margin: 0;
		overflow: hidden;
		font-family: sans-serif;
	}

	.player {
		width: 60px;
		height: 60px;
		position: absolute;

		background-image: url("https://sok.se/images/18.140fa93719c2c511ec5f13b/1770567764998/Freeski.Martin.Nordqvist_685x695_2026.jpg");
		background-size: cover;
		background-position: center;
	}

	.goal {
		width: 60px;
		height: 60px;
		position: absolute;
	}

	#winnerMessage {
		position: fixed;
		top: 50%;
		left: 50%;
		transform: translate(-50%, -50%);
		background: white;
		padding: 20px 40px;
		font-size: 24px;
		border: 3px solid black;
		border-radius: 10px;
	}
</style>

<div class="player" style="left: {left}px; top: {top}px;"></div>

<img 
	class="goal"
	src="data:image/jpeg;base64,"
	alt="Skidmål"
	style="left: {goalLeft}px; top: {goalTop}px;"
/>

{#if winner}
	<div id="winnerMessage"> Du vann! </div>
{/if}

<svelte:window on:keydown={onKeyDown} />